import { useEffect, useState } from "react";
import axios from "axios";

export default function Relay() {
  const [live, setLive] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const url =
          "https://m.koreabaseball.com/ws/Kbo.asmx/GetLiveText?&le_id=1&sr_id=0&g_id=20250918WOOB0&inning=1&order=DESC";

        const { data } = await axios.get(url, {
          headers: {
            "User-Agent":
              "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/140.0.0.0 Safari/537.36",
          },
        });

        const parsed = typeof data === "string" ? JSON.parse(data) : data;

        console.log(data);

        setLive(parsed);
      } catch (err) {
        console.error("API 요청 실패:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) return <p className="text-center p-4">불러오는 중...</p>;
  if (!live) return <p className="text-center p-4">데이터가 없습니다.</p>;

  return (
    <div className="max-w-2xl mx-auto p-4">
      <h1 className="text-xl font-bold mb-4">KBO 문자중계</h1>
      <div className="border rounded-lg p-4 bg-white shadow">
        <h2 className="text-lg font-semibold">
          {live.BAT_ORDER_NO}번 타자 {live.BAT_P_NM}
        </h2>
        <ul className="mt-3 space-y-2">
          {live.listData.map((play, idx) => (
            <li
              key={idx}
              className="p-2 border-b last:border-none text-sm"
            >
              {play.LIVETEXT_IF}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
